import { useRef, useEffect } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { OrbitControls } from '@react-three/drei';

const InstancedBoxes = ({ count = 1000 }) => {
  // InstancedMeshýØÿ ý░©ýí░
  const meshRef = useRef<THREE.InstancedMesh>(null);

  // ý×äýï£ Û░Øý▓┤Ùôñ
  const tempObject = new THREE.Object3D();
  const tempColor = new THREE.Color();

  useEffect(() => {
    const instancedMesh = meshRef.current!;

    // ý┤êÛ©░ ý£äý╣ÿýÖÇ ýâëýâü ýäñýáò
    for (let i = 0; i < count; i++) {
      // Ù×£Ùìñ ý£äý╣ÿ ýäñýáò
      tempObject.position.set(Math.random() * 100 - 50, Math.random() * 100 - 50, Math.random() * 100 - 50);

      // Ù×£Ùìñ ÝÜîýáä
      tempObject.rotation.set(Math.random() * Math.PI, Math.random() * Math.PI, Math.random() * Math.PI);

      // Ù×£Ùìñ Ýü¼Û©░
      const scale = 0.5 + Math.random() * 1;
      tempObject.scale.set(scale, scale, scale);

      // ÝûëÙá¼ ýùàÙì░ýØ┤Ýè©
      tempObject.updateMatrix();

      // ýØ©ýèñÝä┤ýèñýùÉ ÝûëÙá¼ ýáüýÜ®
      instancedMesh.setMatrixAt(i, tempObject.matrix);

      // ýØ©ýèñÝä┤ýèñÙ│ä ýâëýâü ýäñýáò
      tempColor.setHSL(Math.random(), 0.5, 0.5);
      instancedMesh.setColorAt(i, tempColor);
    }

    // Ù│ÇÛ▓¢ýé¼Ýò¡ ýáüýÜ®
    instancedMesh.instanceMatrix.needsUpdate = true;
    if (instancedMesh.instanceColor) instancedMesh.instanceColor.needsUpdate = true;
  }, [count]);

  // ýòáÙïêÙ®öýØ┤ýàÿ
  useFrame((state) => {
    const time = state.clock.getElapsedTime();
    const instancedMesh = meshRef.current!;

    for (let i = 0; i < count; i++) {
      // Û░ü ýØ©ýèñÝä┤ýèñýØÿ Ýÿäý×¼ ÝûëÙá¼ Û░Çýá©ýÿñÛ©░
      instancedMesh.getMatrixAt(i, tempObject.matrix);
      // MatrixÙÑ╝ ÙÂäÝò┤Ýòÿýù¼ ý£äý╣ÿ, ÝÜîýáä, Ýü¼Û©░ ýáòÙ│┤ ýÂöýÂ£
      tempObject.matrix.decompose(tempObject.position, tempObject.quaternion, tempObject.scale);

      // ÝÜîýáä ýòáÙïêÙ®öýØ┤ýàÿ
      tempObject.rotation.x = time * 0.1 + i * 0.1;

      // ÝûëÙá¼ ýùàÙì░ýØ┤Ýè©
      tempObject.updateMatrix();
      instancedMesh.setMatrixAt(i, tempObject.matrix);
    }

    instancedMesh.instanceMatrix.needsUpdate = true;
  });

  return (
    <instancedMesh ref={meshRef} args={[undefined, undefined, count]}>
      <boxGeometry />
      <meshPhongMaterial />
    </instancedMesh>
  );
};

// ýé¼ýÜ® ýÿêýï£
const Scene = () => (
  <Canvas>
    <ambientLight intensity={0.5} />
    <pointLight position={[10, 10, 10]} />
    <InstancedBoxes count={1000} />
    <OrbitControls />
  </Canvas>
);

export default Scene;
